using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// -- Tool implementations ------------------------------------------------

var notepad = new Notepad();

/// <summary>Searches the web for a given query and returns result snippets.</summary>
[Description("Searches the web for a given query and returns a list of result titles, URLs, and snippets.")]
static string WebSearch(
    [Description("The search query string")] string query,
    [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
{
    // Simulated search results for demonstration.
    // Replace this body with a real search API call (e.g. Bing Search, Google Custom Search).
    var random = new Random(query.GetHashCode());
    maxResults = Math.Clamp(maxResults, 1, 10);

    var sb = new StringBuilder();
    sb.AppendLine($"Search results for: \"{query}\"");
    sb.AppendLine();

    var domains = new[] { "en.wikipedia.org", "arxiv.org", "nature.com", "bbc.com", "reuters.com",
                          "techcrunch.com", "github.com", "stackoverflow.com", "medium.com", "scholar.google.com" };
    var adjectives = new[] { "comprehensive", "recent", "detailed", "peer-reviewed", "breaking",
                             "in-depth", "preliminary", "landmark", "meta-analysis of", "overview of" };

    for (int i = 1; i <= maxResults; i++)
    {
        var domain = domains[random.Next(domains.Length)];
        var adj = adjectives[random.Next(adjectives.Length)];
        sb.AppendLine($"  [{i}] \"{adj} {query}\" — https://{domain}/article/{random.Next(10000, 99999)}");
        sb.AppendLine($"      Snippet: This {adj} resource covers key aspects of {query}, " +
                      $"including recent developments, expert analysis, and practical implications.");
        sb.AppendLine();
    }

    return sb.ToString();
}

// -- Main ----------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine("ℹ  Set OPENAI_API_KEY to use a real LLM. Running in demo mode with a stub client.");
    Console.ResetColor();
    Console.WriteLine();
}

// Build the IChatClient – either a real OpenAI client or a local stub.
IChatClient innerClient = !string.IsNullOrWhiteSpace(apiKey)
    ? new OpenAI.OpenAIClient(apiKey)
          .GetChatClient("gpt-4o")
          .AsIChatClient()
    : new StubChatClient();

// Wrap the client with the function-invoking middleware so the agent can call tools.
IChatClient chatClient = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

// Register the tools the agent may invoke.
var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(notepad.SaveNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

// Create the research agent.
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches a topic by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web multiple times with varied queries to gather diverse information.
        2. Save important findings as notes using the note-taking tool.
        3. After gathering enough information (at least 3-5 searches), retrieve your notes
           and produce a well-structured summary of your findings with key takeaways.
        Always cite the sources you found. Be thorough but concise.
        """,
    tools: tools);

// Run the interactive loop.
AgentSession? session = null;

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Enter a research topic (or 'quit' to exit): ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)");
    Console.ResetColor();
    Console.WriteLine();

    notepad.Clear();

    var response = await agent.RunAsync($"Research the following topic and provide a summary: {topic}", session);
    session = response.Session;

    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine("── Research Summary ─────────────────────────────────");
    Console.ResetColor();
    Console.WriteLine(response.Text);
    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

// -- Helper classes -------------------------------------------------------

/// <summary>A simple notepad that the agent uses to store research findings.</summary>
sealed class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record important findings from web searches.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content / finding")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"Note #{i + 1} — {_notes[i].Title}\n{_notes[i].Content}\n");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

/// <summary>
/// A stub <see cref="IChatClient"/> used when no API key is available.
/// It simulates the agent calling tools and producing a final summary.
/// </summary>
sealed class StubChatClient : IChatClient
{
    private int _turn;

    public void Dispose() { }

    public object? GetService(Type serviceType, object? serviceKey = null)
        => serviceType == typeof(IChatClient) ? this : null;

    public IAsyncEnumerable<ChatResponseUpdate> GetStreamingResponseAsync(
        IEnumerable<ChatMessage> chatMessages, ChatOptions? options = null, CancellationToken cancellationToken = default)
        => throw new NotSupportedException();

    public Task<ChatResponse> GetResponseAsync(
        IEnumerable<ChatMessage> chatMessages, ChatOptions? options = null, CancellationToken cancellationToken = default)
    {
        var messages = chatMessages.ToList();
        var userText = messages.LastOrDefault(m => m.Role == ChatRole.User)?.Text ?? "";
        var tools = options?.Tools?.OfType<AIFunction>().ToList() ?? [];

        // Extract the topic from the user message.
        var topic = userText.Contains(':') ? userText[(userText.LastIndexOf(':') + 1)..].Trim() : userText;

        ChatResponse response = _turn switch
        {
            // Turn 0: call WebSearch
            0 => MakeToolCall("WebSearch", new Dictionary<string, object?> { ["query"] = topic, ["maxResults"] = 5 }),
            // Turn 1: call SaveNote with search results
            1 => MakeToolCall("SaveNote", new Dictionary<string, object?>
            {
                ["title"] = $"Initial findings on {topic}",
                ["content"] = $"Found several resources covering key aspects of {topic} including recent developments and expert analysis."
            }),
            // Turn 2: search for more specific info
            2 => MakeToolCall("WebSearch", new Dictionary<string, object?> { ["query"] = $"{topic} latest developments 2025", ["maxResults"] = 3 }),
            // Turn 3: save another note
            3 => MakeToolCall("SaveNote", new Dictionary<string, object?>
            {
                ["title"] = $"Recent developments in {topic}",
                ["content"] = $"Recent studies and reports highlight emerging trends in {topic} with significant implications for the field."
            }),
            // Turn 4: search for practical applications
            4 => MakeToolCall("WebSearch", new Dictionary<string, object?> { ["query"] = $"{topic} practical applications", ["maxResults"] = 3 }),
            // Turn 5: save final note
            5 => MakeToolCall("SaveNote", new Dictionary<string, object?>
            {
                ["title"] = $"Practical applications of {topic}",
                ["content"] = $"Practical applications of {topic} span several industries including technology, healthcare, and education."
            }),
            // Turn 6: retrieve notes
            6 => MakeToolCall("GetNotes", new Dictionary<string, object?>()),
            // Turn 7+: final summary
            _ => new ChatResponse(new ChatMessage(ChatRole.Assistant,
                $"""
                # Research Summary: {topic}

                ## Overview
                Based on comprehensive web research, here are the key findings on **{topic}**:

                ## Key Findings
                1. **Foundational Research** — Multiple authoritative sources provide comprehensive coverage of {topic},
                   including peer-reviewed articles and expert analyses.
                2. **Recent Developments** — The field has seen significant recent activity, with new studies and reports
                   highlighting emerging trends and breakthroughs.
                3. **Practical Applications** — Applications of {topic} span several industries including technology,
                   healthcare, and education, with growing real-world impact.

                ## Sources Consulted
                - Wikipedia, arXiv, and Nature for foundational knowledge
                - Reuters and BBC for recent news coverage
                - TechCrunch and Medium for practical perspectives

                ## Key Takeaways
                - {topic} is an actively evolving area with significant cross-disciplinary impact.
                - Recent developments suggest accelerating progress and broadening applications.
                - Multiple reliable sources confirm the growing importance of this topic.

                *This summary was compiled from {_turn} search queries and multiple saved research notes.*
                """))
        };

        _turn++;
        return Task.FromResult(response);
    }

    private static ChatResponse MakeToolCall(string name, IDictionary<string, object?> args)
    {
        var callContent = new FunctionCallContent(Guid.NewGuid().ToString(), name, args);
        return new ChatResponse(new ChatMessage(ChatRole.Assistant, [callContent]));
    }
}

