 // -- Tool implementations ------------------------------------------------

 var notepad = new Notepad();

 /// <summary>Searches the web for a given query and returns result snippets.</summary>
 [Description("Searches the web for a given query and returns a list of result titles, URLs, and snippets.")]
 static string WebSearch(
     [Description("The search query string")] string query,
     [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
 {
     // Simulated search results for demonstration.
     // Replace this body with a real search API call (e.g. Bing Search, Google Custom Search).
     var random = new Random(query.GetHashCode());
     maxResults = Math.Clamp(maxResults, 1, 10);

     var sb = new StringBuilder();
     sb.AppendLine($"Search results for: \"{query}\"");
     sb.AppendLine();

     var domains = new[] { "en.wikipedia.org", "arxiv.org", "nature.com", "bbc.com", "reuters.com",
                           "techcrunch.com", "github.com", "stackoverflow.com", "medium.com", "scholar.google.com" };
     var adjectives = new[] { "comprehensive", "recent", "detailed", "peer-reviewed", "breaking",
                              "in-depth", "preliminary", "landmark", "meta-analysis of", "overview of" };

     for (int i = 1; i <= maxResults; i++)
     {
         var domain = domains[random.Next(domains.Length)];
         var adj = adjectives[random.Next(adjectives.Length)];
         sb.AppendLine($"  [{i}] \"{adj} {query}\" — https://{domain}/article/{random.Next(10000, 99999)}");
         sb.AppendLine($"      Snippet: This {adj} resource covers key aspects of {query}, " +
                       $"including recent developments, expert analysis, and practical implications.");
         sb.AppendLine();
     }

     return sb.ToString();
 }

 // -- Main ----------------------------------------------------------------

 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       🔍 AI Research Agent           ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
 if (string.IsNullOrWhiteSpace(apiKey))
 {
     Console.ForegroundColor = ConsoleColor.Yellow;
     Console.WriteLine("ℹ  Set OPENAI_API_KEY to use a real LLM. Running in demo mode with a stub client.");
     Console.ResetColor();
     Console.WriteLine();
 }

 // Build the IChatClient – either a real OpenAI client or a local stub.
 IChatClient innerClient = !string.IsNullOrWhiteSpace(apiKey)
     ? new OpenAI.OpenAIClient(apiKey)
           .GetChatClient("gpt-4o")
           .AsIChatClient()
     : new StubChatClient();

 // Wrap the client with the function-invoking middleware so the agent can call tools.
 IChatClient chatClient = new ChatClientBuilder(innerClient)
     .UseFunctionInvocation()
     .Build();

 // Register the tools the agent may invoke.
 var tools = new AITool[]
 {
     AIFunctionFactory.Create(WebSearch),
     AIFunctionFactory.Create(notepad.SaveNote),
     AIFunctionFactory.Create(notepad.GetNotes),
 };

 // Create the research agent.
 var agent = new ChatClientAgent(
     chatClient,
     name: "ResearchAgent",
     description: "An AI agent that researches a topic by searching the web and taking notes.",
     instructions: """
         You are a research assistant. When given a topic:
         1. Search the web multiple times with varied queries to gather diverse information.
         2. Save important findings as notes using the note-taking tool.
         3. After gathering enough information (at least 3-5 searches), retrieve your notes
            and produce a well-structured summary of your findings with key takeaways.
         Always cite the sources you found. Be thorough but concise.
         """,
     tools: tools);

 // Run the interactive loop.
 while (true)
 {
     Console.ForegroundColor = ConsoleColor.Cyan;
     Console.Write("Enter a research topic (or 'quit' to exit): ");
     Console.ResetColor();

     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     Console.WriteLine();
     Console.ForegroundColor = ConsoleColor.DarkGray;
     Console.WriteLine("Researching… (the agent will search the web and take notes)");
     Console.ResetColor();
     Console.WriteLine();

     notepad.Clear();

     // Each topic gets a fresh session so conversation history doesn't leak across topics.
     var session = await agent.CreateSessionAsync();
     var response = await agent.RunAsync(
         $"Research the following topic and provide a summary: {topic}", session);

     Console.ForegroundColor = ConsoleColor.Green;
     Console.WriteLine("── Research Summary ─────────────────────────────────");
     Console.ResetColor();
     Console.WriteLine(response.Text);
     Console.WriteLine();
 }

